        pickersNotified: z.boolean().optional(),
        waveOptimizationEnabled: z.boolean().optional(),
        batchPickingEnabled: z.boolean().optional(),
        autoReplenishmentEnabled: z.boolean().optional(),
        isActive: z.boolean().optional(),
